#if defined(ENABLE_DP)
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#if defined(ENABLE_HP)
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

inline class_T madd(const class_T a, const class_T b, const class_T c) {
  return a * b + c;
}

inline int equalv(const class_T a, const class_T b) {
#if defined(ENABLE_HP)
  return all(a == b);
#else
  return a == b;
#endif
}

__kernel void benchmark_func(const class_T seed, __global class_T* g_data) {
#ifdef BLOCK_STRIDED
  const uint stride = (uint)get_local_size(0);
  const uint idx =
      (uint)get_group_id(0) * stride * (uint)ELEMENTS_PER_THREAD +
      (uint)get_local_id(0);
#else
  const uint stride = (uint)get_global_size(0);
  const uint idx = (uint)get_global_id(0);
#endif

  const uint big_stride = (uint)get_global_size(0) * (uint)ELEMENTS_PER_THREAD;

  class_T tmps[ELEMENTS_PER_THREAD];

  for (uint k = 0; k < (uint)FUSION_DEGREE; ++k) {
    for (uint j = 0; j < (uint)ELEMENTS_PER_THREAD; ++j) {
      const size_t pos = (size_t)idx + (size_t)j * (size_t)stride +
                         (size_t)k * (size_t)big_stride;
      tmps[j] = g_data[pos];

      for (int i = 0; i < (int)COMPUTE_ITERATIONS; ++i) {
        tmps[j] = madd(tmps[j], tmps[j], seed);
      }
    }

    class_T sum = (class_T)(0);
    for (uint j = 0; j + 1 < (uint)ELEMENTS_PER_THREAD; j += 2) {
      sum = madd(tmps[j], tmps[j + 1], sum);
    }

#if (ELEMENTS_PER_THREAD & 1)
    sum = sum + tmps[ELEMENTS_PER_THREAD - 1];
#endif

    if (equalv(sum, (class_T)(-1))) {
      g_data[(size_t)idx + (size_t)k * (size_t)big_stride] = sum;
    }
  }
}
